// src/tools/lsp/server-installation.ts
function isServerInstalled(command) {
  if (command.length === 0)
    return false;
  const cmd = command[0];
  if (cmd.includes("/") || cmd.includes("\\")) {
    if (existsSync37(cmd))
      return true;
  }
  const isWindows = process.platform === "win32";
  let exts = [""];
  if (isWindows) {
    const pathExt = process.env.PATHEXT || "";
    if (pathExt) {
      const systemExts = pathExt.split(";").filter(Boolean);
      exts = [...new Set([...exts, ...systemExts, ".exe", ".cmd", ".bat", ".ps1"])];
    } else {
      exts = ["", ".exe", ".cmd", ".bat", ".ps1"];
    }
  }
  let pathEnv = process.env.PATH || "";
  if (isWindows && !pathEnv) {
    pathEnv = process.env.Path || "";
  }
  const paths = pathEnv.split(delimiter2);
  for (const p2 of paths) {
    for (const suffix of exts) {
      if (existsSync37(join39(p2, cmd + suffix))) {
        return true;
      }
    }
  }
  for (const base of getLspServerAdditionalPathBases(process.cwd())) {
    for (const suffix of exts) {
      if (existsSync37(join39(base, cmd + suffix))) {
        return true;
      }
    }
  }
  if (cmd === "bun" || cmd === "node") {
    return true;
  }
  return false;
}

// src/tools/lsp/server-resolution.ts
function getAllServers() {
  const configs = loadAllConfigs();
  const servers = getMergedServers();
  const disabled = new Set;
  for (const config2 of configs.values()) {
    if (!config2.lsp)
      continue;
    for (const [id, entry] of Object.entries(config2.lsp)) {
      if (entry.disabled)
        disabled.add(id);
    }
  }
  const result = [];
  const seen = new Set;
  for (const server2 of servers) {
    if (seen.has(server2.id))
      continue;
    result.push({
      id: server2.id,
      installed: isServerInstalled(server2.command),
      extensions: server2.extensions,
      disabled: false,
      source: server2.source,
      priority: server2.priority
    });
    seen.add(server2.id);
  }
  for (const id of disabled) {
    if (seen.has(id))
      continue;
    const builtin = BUILTIN_SERVERS[id];
    result.push({
      id,
      installed: builtin ? isServerInstalled(builtin.command) : false,
      extensions: builtin?.extensions || [],
      disabled: true,
      source: "disabled",
      priority: 0
    });
  }
  return result;
}
